# Prototypes and Object.create

Every JavaScript object has a hidden link to another object called its **prototype**. When you access a property the object doesn't have directly, JavaScript walks the prototype chain until it finds one.

```javascript
const parent = {
  greet() { return `hello from ${this.name}`; }
};

const child = Object.create(parent);
child.name = 'Rex';

child.greet();  // => 'hello from Rex'
```

`Object.create(parent)` builds a new object whose prototype is `parent`. `child` has no `greet` property of its own — calling `child.greet()` finds it on the prototype.

This is **prototype-based inheritance**, and it's the foundation under every JavaScript class.

A class, in its simplest form, is just:

1. A **prototype object** that holds the shared methods.
2. A **factory** that creates new instances linked to that prototype.

```javascript
const circleMethods = {
  area() { return Math.PI * this.radius ** 2; },
};

function makeCircle(radius) {
  const instance = Object.create(circleMethods);
  instance.radius = radius;
  return instance;
}

const c = makeCircle(5);
c.area();  // 78.539...
```

That's all a class is, at bottom. Everything else — constructors, `new`, `class` syntax — is convenience layered on top.

In the next lesson you'll build your own factory-based class.

lessons.starter:
function range(from, to) {
  // Create an object that inherits from range.methods,
  // then set .from and .to on it, and return it.
}

range.methods = {
  includes(x) { return this.from <= x && x <= this.to; },
  toString() { return `(${this.from}...${this.to})`; },
};

module.exports = { range };

lessons.solution:
function range(from, to) {
  const r = Object.create(range.methods);
  r.from = from;
  r.to = to;
  return r;
}

range.methods = {
  includes(x) { return this.from <= x && x <= this.to; },
  toString() { return `(${this.from}...${this.to})`; },
};

module.exports = { range };

lessons.tests:
const { range } = require('./user');

test('from and to are stored on the instance', () => {
  const r = range(1, 10);
  expect(r.from).toBe(1);
  expect(r.to).toBe(10);
});

test('includes reports membership correctly', () => {
  const r = range(1, 10);
  expect(r.includes(5)).toBe(true);
  expect(r.includes(1)).toBe(true);
  expect(r.includes(10)).toBe(true);
  expect(r.includes(0)).toBe(false);
  expect(r.includes(11)).toBe(false);
});

test('toString renders the range', () => {
  expect(range(1, 5).toString()).toBe('(1...5)');
});

test('instances share the same method references (prototype)', () => {
  const a = range(1, 3);
  const b = range(100, 200);
  expect(a.includes).toBe(b.includes);
  expect(a.toString).toBe(b.toString);
});

