# Constructor functions

The factory pattern works, but it's verbose. JavaScript has a built-in way to make a function act like a class: the **constructor**.

A constructor is just a regular function you invoke with `new`:

```javascript
function Circle(radius) {
  this.radius = radius;
}

Circle.prototype.area = function () {
  return Math.PI * this.radius ** 2;
};

const c = new Circle(5);
c.area();  // 78.539...
```

The `new` keyword does four things, in order:

1. Creates a fresh empty object.
2. Sets its prototype to `Circle.prototype`.
3. Calls `Circle` with `this` bound to the new object.
4. Returns `this` (unless the constructor explicitly returns something else).

So `new Circle(5)` is roughly:

```javascript
const instance = Object.create(Circle.prototype);
Circle.call(instance, 5);
// → instance
```

The idiom around constructors:

- **Capitalize** the function name (`Circle`, not `circle`) so humans know to use `new`.
- Define instance state inside the function body with `this.x = ...`.
- Define shared methods on `Constructor.prototype`.

This is the pattern you'll find in any pre-ES6 codebase, and what the modern `class` keyword compiles down to under the hood.

lessons.starter:
function Range(from, to) {
  // Assign from/to to `this` here
}

// Attach shared methods to Range.prototype:
// Range.prototype.includes = function (x) { ... };
// Range.prototype.toString = function () { ... };

module.exports = { Range };

lessons.solution:
function Range(from, to) {
  this.from = from;
  this.to = to;
}

Range.prototype.includes = function (x) {
  return this.from <= x && x <= this.to;
};

Range.prototype.toString = function () {
  return `(${this.from}...${this.to})`;
};

module.exports = { Range };

lessons.tests:
const { Range } = require('./user');

test('new Range stores from and to', () => {
  const r = new Range(1, 10);
  expect(r.from).toBe(1);
  expect(r.to).toBe(10);
});

test('includes works', () => {
  const r = new Range(1, 10);
  expect(r.includes(5)).toBe(true);
  expect(r.includes(11)).toBe(false);
});

test('toString renders correctly', () => {
  expect(new Range(1, 5).toString()).toBe('(1...5)');
});

test('instances share methods via prototype', () => {
  const a = new Range(1, 3);
  const b = new Range(100, 200);
  expect(a.includes).toBe(b.includes);
});

test('instances are linked to Range.prototype', () => {
  const r = new Range(1, 2);
  expect(Object.getPrototypeOf(r)).toBe(Range.prototype);
  expect(r instanceof Range).toBe(true);
});

