class Range {
  constructor(from, to) {
    this.from = from;
    this.to = to;
  }

  includes(x) { return this.from <= x && x <= this.to; }
  toString()  { return `(${this.from}...${this.to})`; }
}

module.exports = { Range };

lessons.tests:
const { Range } = require('./user');

test('Range stores from and to', () => {
  const r = new Range(1, 10);
  expect(r.from).toBe(1);
  expect(r.to).toBe(10);
});

test('includes works', () => {
  expect(new Range(1, 10).includes(5)).toBe(true);
  expect(new Range(1, 10).includes(11)).toBe(false);
});

test('toString renders correctly', () => {
  expect(new Range(1, 5).toString()).toBe('(1...5)');
});

test('methods live on the prototype, not each instance', () => {
  const r = new Range(1, 2);
  expect(Range.prototype.includes).toBe(r.includes);
  expect(Object.hasOwn(r, 'includes')).toBe(false);
});

