# Static, getters, and private

Modern classes support three features that significantly improve what you can express.

## Static methods

A **static method** belongs to the class itself, not to instances. Prefix it with `static`:

```javascript
class Range {
  constructor(from, to) { this.from = from; this.to = to; }

  static fromArray(arr) {
    return new Range(arr[0], arr[arr.length - 1]);
  }
}

Range.fromArray([3, 7]);  // new Range(3, 7)
```

Think of static methods as "constructors with a different signature" or "helpers attached to the class."

## Getters and setters

Define computed properties with `get`/`set`:

```javascript
class Temperature {
  constructor(celsius) { this._c = celsius; }

  get fahrenheit() { return this._c * 9/5 + 32; }
  set fahrenheit(f) { this._c = (f - 32) * 5/9; }
}

const t = new Temperature(100);
t.fahrenheit;      // 212
t.fahrenheit = 32;
t._c;              // 0
```

Callers read and assign `t.fahrenheit` like a regular property — the getter/setter are invoked behind the scenes.

## Private fields (`#`)

Any field prefixed with `#` is private to the class:

```javascript
class Counter {
  #count = 0;
  increment() { this.#count++; }
  get value() { return this.#count; }
}

const c = new Counter();
c.increment();
c.value;     // 1
c.#count;    // SyntaxError — not accessible outside the class
```

Private fields give you real encapsulation — the leading `#` isn't a convention, it's enforced by the engine.

lessons.starter:
class Complex {
  // Declare private fields here

  constructor(real, imag) {
    // Store the args in the private fields
  }

  get real() {}
  get imag() {}
  get magnitude() {}

  add(other) {}

  static zero() {}

  toString() {}
}

module.exports = { Complex };

lessons.solution:
class Complex {
  #real;
  #imag;

  constructor(real, imag) {
    this.#real = real;
    this.#imag = imag;
  }

  get real() { return this.#real; }
  get imag() { return this.#imag; }
  get magnitude() {
    return Math.sqrt(this.#real ** 2 + this.#imag ** 2);
  }

  add(other) {
    return new Complex(this.#real + other.real, this.#imag + other.imag);
  }

  static zero() {
    return new Complex(0, 0);
  }

  toString() {
    const sign = this.#imag >= 0 ? '+' : '-';
    return `${this.#real} ${sign} ${Math.abs(this.#imag)}i`;
  }
}

module.exports = { Complex };

lessons.tests:
const { Complex } = require('./user');

test('stores real and imag via getters', () => {
  const c = new Complex(3, 4);
  expect(c.real).toBe(3);
  expect(c.imag).toBe(4);
});

test('magnitude is sqrt(real² + imag²)', () => {
  const c = new Complex(3, 4);
  expect(c.magnitude).toBe(5);
});

test('add returns a new Complex with summed parts', () => {
  const a = new Complex(1, 2);
  const b = new Complex(3, 4);
  const sum = a.add(b);
  expect(sum.real).toBe(4);
  expect(sum.imag).toBe(6);
});

test('add does not mutate its operands', () => {
  const a = new Complex(1, 2);
  const b = new Complex(3, 4);
  a.add(b);
  expect(a.real).toBe(1);
  expect(b.real).toBe(3);
});

test('Complex.zero is a static constructor', () => {
  const z = Complex.zero();
  expect(z.real).toBe(0);
  expect(z.imag).toBe(0);
});

test('toString renders positive imaginary part', () => {
  expect(new Complex(3, 4).toString()).toBe('3 + 4i');
});

test('toString renders negative imaginary part', () => {
  expect(new Complex(3, -4).toString()).toBe('3 - 4i');
});

