  includes(x) { return this.from <= x && x <= this.to; }
  toString()  { return `(${this.from}...${this.to})`; }
}

class NumericRange extends Range {
  // Add a `length` getter, `toArray()` method, and override `toString()`.
}

module.exports = { Range, NumericRange };

lessons.solution:
class Range {
  constructor(from, to) {
    this.from = from;
    this.to = to;
  }

  includes(x) { return this.from <= x && x <= this.to; }
  toString()  { return `(${this.from}...${this.to})`; }
}

class NumericRange extends Range {
  get length() { return this.to - this.from + 1; }

  toArray() {
    const out = [];
    for (let i = this.from; i <= this.to; i++) out.push(i);
    return out;
  }

  toString() { return `${super.toString()} [${this.length} elements]`; }
}

module.exports = { Range, NumericRange };

lessons.tests:
const { Range, NumericRange } = require('./user');

test('NumericRange extends Range', () => {
  expect(new NumericRange(1, 5) instanceof Range).toBe(true);
  expect(new NumericRange(1, 5) instanceof NumericRange).toBe(true);
});

test('inherits includes from Range', () => {
  const r = new NumericRange(1, 10);
  expect(r.includes(5)).toBe(true);
  expect(r.includes(11)).toBe(false);
});

test('length is to - from + 1', () => {
  expect(new NumericRange(1, 5).length).toBe(5);
  expect(new NumericRange(0, 0).length).toBe(1);
});

test('toArray returns the integer sequence', () => {
  expect(new NumericRange(1, 5).toArray()).toEqual([1, 2, 3, 4, 5]);
  expect(new NumericRange(10, 12).toArray()).toEqual([10, 11, 12]);
});

test('toString includes length via super.toString', () => {
  expect(new NumericRange(1, 5).toString()).toBe('(1...5) [5 elements]');
});
